import com.pinterest.ktlint.ruleset.standard.StandardRule
import org.jetbrains.kotlin.com.intellij.lang.ASTNode
import org.jetbrains.kotlin.com.intellij.psi.impl.source.tree.LeafPsiElement
import org.jetbrains.kotlin.com.intellij.psi.impl.source.tree.PsiCommentImpl
import org.jetbrains.kotlin.psi.KtAnnotationEntry
import org.jetbrains.kotlin.psi.KtFileAnnotationList
import org.jetbrains.kotlin.psi.psiUtil.startOffset

/**
 * Converts legacy ktlint-disable/ktlint-enable directives to @Suppress annotations.
 * This rule should not be suppressed itself, even if all ktlint rules are suppressed.
 */
public class KtlintDirectiveToSuppressionRule :
    StandardRule(
        id = "ktlint-suppression-rule",
        visitorModifiers = setOf(
            // Run early to convert directives before other rules process them
            RunAfterRule(SPACING_AROUND_COLON_RULE_ID, REGARDLESS_WHETHER_RUN_AFTER_RULE_IS_LOADED_OR_DISABLED)
        ),
    ) {

    override fun beforeVisitChildNodes(
        node: ASTNode,
        autoCorrect: Boolean,
        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
    ) {
        when (node.elementType) {
            EOL_COMMENT -> handleEolComment(node, autoCorrect, emit)
            BLOCK_COMMENT -> handleBlockComment(node, autoCorrect, emit)
        }
    }

    private fun handleEolComment(
        node: ASTNode,
        autoCorrect: Boolean,
        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
    ) {
        val commentText = node.text.removePrefix("//").trim()
        val parts = commentText.split(" ").filter { it.isNotEmpty() }

        if (parts.isNotEmpty() && parts[0] == "ktlint-disable") {
            val ruleIds = parts.drop(1).map { normalizeRuleId(it) }.filter { it.isNotEmpty() }
            emit(
                node.startOffset,
                "Replace ktlint-disable directive with @Suppress annotation",
                true
            )

            if (autoCorrect) {
                convertEolDirectiveToSuppression(node, ruleIds)
            }
        }
    }

    private fun handleBlockComment(
        node: ASTNode,
        autoCorrect: Boolean,
        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
    ) {
        val commentText = node.text.removePrefix("/*").removeSuffix("*/").trim()
        val parts = commentText.split(" ").filter { it.isNotEmpty() }

        if (parts.isNotEmpty() && (parts[0] == "ktlint-disable" || parts[0] == "ktlint-enable")) {
            when (parts[0]) {
                "ktlint-disable" -> {
                    val ruleIds = parts.drop(1).map { normalizeRuleId(it) }.filter { it.isNotEmpty() }
                    emit(
                        node.startOffset,
                        "Replace ktlint-disable directive with @Suppress annotation",
                        true
                    )

                    if (autoCorrect) {
                        convertBlockDirectiveToSuppression(node, ruleIds)
                    }
                }
                "ktlint-enable" -> {
                    emit(
                        node.startOffset,
                        "Remove ktlint-enable directive (no longer needed with @Suppress)",
                        true
                    )

                    if (autoCorrect) {
                        removeEnableDirective(node)
                    }
                }
            }
        }
    }

    private fun convertEolDirectiveToSuppression(node: ASTNode, ruleIds: List<String>) {
        val suppressValue = if (ruleIds.isEmpty()) {
            "\"ktlint\""
        } else {
            ruleIds.joinToString(", ") { "\"ktlint:$it\"" }
        }

        // Find the statement that should be suppressed (typically on the same line before the comment)
        val statementNode = findStatementForEolComment(node)
        if (statementNode != null) {
            addSuppressionAnnotation(statementNode, suppressValue)
        }

        // Remove the comment
        removeNode(node)
    }

    private fun convertBlockDirectiveToSuppression(node: ASTNode, ruleIds: List<String>) {
        val suppressValue = if (ruleIds.isEmpty()) {
            "\"ktlint\""
        } else {
            ruleIds.joinToString(", ") { "\"ktlint:$it\"" }
        }

        // Find what should be suppressed after this block comment
        val targetNode = findTargetForBlockComment(node)
        if (targetNode != null) {
            // Check if this looks like a file-level suppression
            if (isFileLevelSuppression(node)) {
                addFileLevelSuppression(node.treeParent, suppressValue)
            } else {
                addSuppressionAnnotation(targetNode, suppressValue)
            }
        }

        // Remove the block comment
        removeNode(node)
    }

    private fun removeEnableDirective(node: ASTNode) {
        removeNode(node)
    }

    private fun findStatementForEolComment(commentNode: ASTNode): ASTNode? {
        // Look backwards to find the statement on the same line
        var current = commentNode.prevLeaf()
        while (current != null && !current.isWhiteSpaceWithNewline()) {
            if (current.psi != null && !current.text.trim().isEmpty()) {
                return findStatementRoot(current)
            }
            current = current.prevLeaf()
        }
        return null
    }

    private fun findTargetForBlockComment(commentNode: ASTNode): ASTNode? {
        // Look forward to find the next significant statement
        var current = commentNode.nextLeaf()
        while (current != null && current.text.trim().isEmpty()) {
            current = current.nextLeaf()
        }
        return current?.let { findStatementRoot(it) }
    }

    private fun findStatementRoot(node: ASTNode): ASTNode {
        var current = node
        // Traverse up to find a statement-level node that can be annotated
        while (current.treeParent != null) {
            val parent = current.treeParent
            when (parent.elementType.toString()) {
                "FILE" -> break
                "CLASS_BODY", "BLOCK", "SCRIPT" -> break
            }
            current = parent
        }
        return current
    }

    private fun isFileLevelSuppression(commentNode: ASTNode): Boolean {
        // Check if this comment is at the top of the file or before any significant code
        var current = commentNode.prevCodeSibling()
        while (current != null) {
            // If we find any non-import, non-package statement, this is not file-level
            when (current.elementType.toString()) {
                "PACKAGE_DIRECTIVE", "IMPORT_LIST", "IMPORT_DIRECTIVE" -> {
                    current = current.prevCodeSibling()
                    continue
                }
                else -> return false
            }
        }
        return true
    }

    private fun addFileLevelSuppression(fileNode: ASTNode, suppressValue: String) {
        val fileAnnotationList = fileNode.children().find { it.psi is KtFileAnnotationList }
        val suppressAnnotation = "@file:Suppress($suppressValue)\n\n"

        if (fileAnnotationList != null) {
            // Add to existing file annotation list
            val lastAnnotation = fileAnnotationList.children().lastOrNull { it.psi is KtAnnotationEntry }
            if (lastAnnotation != null) {
                val newAnnotation = PsiCommentImpl(EOL_COMMENT, suppressAnnotation)
                lastAnnotation.treeParent.addChild(newAnnotation, lastAnnotation.treeNext)
            }
        } else {
            // Create new file annotation at the beginning
            val firstChild = fileNode.firstChildNode
            val newAnnotation = PsiCommentImpl(EOL_COMMENT, suppressAnnotation)
            fileNode.addChild(newAnnotation, firstChild)
        }
    }

    private fun addSuppressionAnnotation(targetNode: ASTNode, suppressValue: String) {
        val suppressAnnotation = "@Suppress($suppressValue)\n"
        val annotationNode = PsiCommentImpl(EOL_COMMENT, suppressAnnotation)
        targetNode.treeParent.addChild(annotationNode, targetNode)
    }

    private fun removeNode(node: ASTNode) {
        val parent = node.treeParent

        // Also remove trailing whitespace if the comment was on its own line
        val nextSibling = node.treeNext
        if (nextSibling != null && nextSibling.isWhiteSpaceWithNewline()) {
            parent.removeChild(nextSibling)
        }

        parent.removeChild(node)
    }

    private fun normalizeRuleId(ruleId: String): String {
        return when {
            ruleId.startsWith("experimental:") -> ruleId.replace("experimental:", "standard:")
            !ruleId.contains(":") -> "standard:$ruleId"
            else -> ruleId
        }
    }
}

