{"file_path": "/project/ktlint-ruleset-standard/src/test/kotlin/com/pinterest/ktlint/ruleset/standard/rules/KtlintDirectiveToSuppressionRuleTest.kt", "content": "package com.pinterest.ktlint.ruleset.standard.rules

import com.pinterest.ktlint.test.KtLintAssertThat.Companion.assertThatRule
import com.pinterest.ktlint.test.LintViolation
import org.junit.jupiter.api.Test

class KtlintDirectiveToSuppressionRuleTest {
    private val ktlintDirectiveToSuppressionRuleAssertThat = assertThatRule { KtlintDirectiveToSuppressionRule() }

    @Test
    fun `Given code without ktlint directives then no violations are found`() {
        val code =
            """
            val foo = "foo"
            // Regular comment
            /* Regular block comment */
            """.trimIndent()
        ktlintDirectiveToSuppressionRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Given EOL ktlint-disable directive for all rules then violation is reported`() {
        val code =
            """
            val foo = "foo" // ktlint-disable
            """.trimIndent()
        ktlintDirectiveToSuppressionRuleAssertThat(code).hasLintViolation(
            1, 17, "Replace ktlint-disable directive with @Suppress(\"ktlint\") annotation on the preceding statement"
        )
    }

    @Test
    fun `Given EOL ktlint-disable directive for specific rules then violation is reported`() {
        val code =
            """
            val foo = "foo" // ktlint-disable no-multi-spaces max-line-length
            """.trimIndent()
        ktlintDirectiveToSuppressionRuleAssertThat(code).hasLintViolation(
            1, 17, "Replace ktlint-disable directive with @Suppress(\"ktlint:standard:no-multi-spaces\", \"ktlint:standard:max-line-length\") annotation on the preceding statement"
        )
    }

    @Test
    fun `Given EOL ktlint-disable directive with experimental rule then rule is normalized to standard`() {
        val code =
            """
            val foo = "foo" // ktlint-disable experimental:argument-list-wrapping
            """.trimIndent()
        ktlintDirectiveToSuppressionRuleAssertThat(code).hasLintViolation(
            1, 17, "Replace ktlint-disable directive with @Suppress(\"ktlint:standard:argument-list-wrapping\") annotation on the preceding statement"
        )
    }

    @Test
    fun `Given block ktlint-disable directive then violation is reported`() {
        val code =
            """
            /* ktlint-disable */
            val foo = "foo"
            """.trimIndent()
        ktlintDirectiveToSuppressionRuleAssertThat(code).hasLintViolation(
            1, 1, "Replace ktlint-disable block directive with @Suppress(\"ktlint\") annotation on the target declaration"
        )
    }

    @Test
    fun `Given block ktlint-disable directive for specific rules then violation is reported`() {
        val code =
            """
            /* ktlint-disable max-line-length no-multi-spaces */
            val foo = "foo"
            """.trimIndent()
        ktlintDirectiveToSuppressionRuleAssertThat(code).hasLintViolation(
            1, 1, "Replace ktlint-disable block directive with @Suppress(\"ktlint:standard:max-line-length\", \"ktlint:standard:no-multi-spaces\") annotation on the target declaration"
        )
    }

    @Test
    fun `Given ktlint-enable directive then violation is reported`() {
        val code =
            """
            /* ktlint-enable */
            """.trimIndent()
        ktlintDirectiveToSuppressionRuleAssertThat(code).hasLintViolation(
            1, 1, "Remove ktlint-enable directive (no longer needed with @Suppress)"
        )
    }

    @Test
    fun `Given ktlint-enable directive with specific rules then violation is reported`() {
        val code =
            """
            /* ktlint-enable max-line-length */
            """.trimIndent()
        ktlintDirectiveToSuppressionRuleAssertThat(code).hasLintViolation(
            1, 1, "Remove ktlint-enable directive (no longer needed with @Suppress)"
        )
    }

    @Test
    fun `Given rule with colon prefix then it is preserved`() {
        val code =
            """
            val foo = "foo" // ktlint-disable standard:no-multi-spaces custom:my-rule
            """.trimIndent()
        ktlintDirectiveToSuppressionRuleAssertThat(code).hasLintViolation(
            1, 17, "Replace ktlint-disable directive with @Suppress(\"ktlint:standard:no-multi-spaces\", \"ktlint:custom:my-rule\") annotation on the preceding statement"
        )
    }
}"}

